<div class="grid gap-4 md:grid-cols-2"><x-form.input name="smtp_host" label="SMTP Host" :value="$smtpHost" dir-ltr /><x-form.input name="smtp_port" type="number" label="SMTP Port" :value="$smtpPort" dir-ltr /><x-form.input name="smtp_username" label="SMTP Username" :value="$smtpUsername" dir-ltr /><x-form.input name="smtp_password" type="password" label="SMTP Password" value="" dir-ltr help="برای حفظ رمز فعلی، خالی بگذارید." /><x-form.select name="smtp_encryption" label="Encryption" :selected="$smtpEncryption" :options="$smtpEncryptions" /><x-form.input name="smtp_from_address" label="From Email" :value="$smtpFromAddress" dir-ltr /><x-form.input name="smtp_from_name" label="From Name" :value="$smtpFromName" /></div>
